import { useState, lazy, Suspense } from "react";

import { Skeleton, Spinner, useDisclosure } from "@nextui-org/react";

import { links } from "./consts/consts";

const NavbarCustom = lazy(() => import("./sections/NavbarCustom"));
const CartModal = lazy(() => import("./sections/CartModal"));

const Banners = lazy(() => import("./sections/Banners"));
const Formas = lazy(() => import("./sections/Formas"));
const Imanes = lazy(() => import("./sections/Imanes"));
const Otros = lazy(() => import("./sections/Otros"));
const Caracteristicas = lazy(() => import("./sections/Caracteristicas"));
const Faqs = lazy(() => import("./sections/Faqs"));

const Footer = lazy(() => import("./sections/Footer"));

function App() {
  // const [sectionsLoaded, setSectionsLoaded] = useState([]);
  // const [loading, setLoading] = useState(true);
  const [theme, setTheme] = useState("dark");
  const [cart, setCart] = useState({});
  const { isOpen, onOpen, onOpenChange } = useDisclosure();

  const sectionComponents = [
    <Formas />,
    <Imanes links={links} cart={{ value: cart, set: setCart }} />,
    <Otros cart={{ value: cart, set: setCart }} />,
    <Caracteristicas />,
    <Faqs links={links} />,
    <Footer links={links} />,
  ];
  // const sections = sectionIDs.reduce((prev, id, i) => {
  //   return [...prev, { id: id, content: sectionComponents[i] }];
  // }, []);

  const handleTheme = (val) => {
    if (val) {
      document.body.classList?.remove(theme);
      setTheme(val);
      document.body.classList?.add(val);
    }
  };

  // useEffect(() => {
  //   const loadSections = async () => {
  //     for (let i = 0; i < sectionIDs.length; i++) {
  //       await loadSection();
  //       setSectionsLoaded((prev) => [...prev, sectionIDs[i]]);
  //     }

  //     setLoading(false);
  //   };

  //   const loadSection = () => {
  //     return new Promise((resolve) => {
  //       setTimeout(() => {
  //         resolve();
  //       }, 1000);
  //     });
  //   };

  //   loadSections();
  //   // eslint-disable-next-line
  // }, []);

  return (
    <div className="bg-content2 dark:bg-content1 text-foreground font-[menulis] min-h-screen overflow-x-hidden overflow-auto h-[100vh] scroll-smooth sm:scrollbar scrollbar-thumb-custom1 scrollbar-track-custom2-10 scrollbar-w-3 scrollbar-h-3 hover:scrollbar-thumb-custom1-6 ">
      <Suspense>
        <NavbarCustom
          theme={{ value: theme, set: handleTheme }}
          // sectionsLoaded={sectionsLoaded}
          onOpenCart={onOpen}
          cartLength={Object.values(cart).reduce(
            (acc, obj) => acc + Object.keys(obj).length,
            0
          )}
        />
      </Suspense>

      {isOpen && (
        <Suspense
          fallback={
            <span className="absolute w-full h-screen flex items-center justify-center bg-black/50 inset-0 z-50">
              <Spinner />
            </span>
          }
        >
          <CartModal
            isOpen={isOpen}
            onOpenChange={onOpenChange}
            cart={{ value: cart, set: setCart }}
            links={links}
          />
        </Suspense>
      )}

      <main>
        <Suspense
          fallback={
            <Skeleton className="min-h-[600px] xs:min-h-[700px] sm:min-h-[500px]" />
          }
        >
          <Banners />
        </Suspense>

        {/* {sections.map(
          (section) =>
            sectionsLoaded.includes(section.id) && (
              <Suspense key={section.id}>{section.content}</Suspense>
            )
        )}

        {loading && <Spinner className="w-full text-center" />} */}

        {sectionComponents.map((section, i) => (
          <Suspense key={i}>{section}</Suspense>
        ))}
      </main>
    </div>
  );
}

export default App;
